#!/usr/bin/env node
/**
 * gen-vegetation-glbs — author one distinct GLB per vegetation kind for the
 * Plan-stage `DesignElementScenegraphLayer` (deck.gl).
 *
 * Phase 3 of ADR `2026-05-11-atlas-deckgl-scenegraph-migration.md`. Adds
 * trees and shrubs to the catalog. Hedgerow is line geometry and renders
 * via the 2D fill fallback in `BeV2GenericLayer`, so it has no GLB here.
 *
 * Output GLBs are CC0 — generated by code in this repo. See
 * `public/models/vegetation/NOTICE.md`.
 *
 * Convention (matches structure GLBs): unit-normalized so the trunk sits at
 * the origin and the canopy top sits at Y=1. `DesignElementScenegraphLayer`
 * scales the model to the kind's footprintM × heightM × footprintM.
 *
 * Run via:    pnpm --filter @ogden/web gen:models
 */

import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';
import { writeGLB } from './lib/glb-writer.mjs';
import { cylinder, cone, dome, merge } from './lib/primitives.mjs';

const __dirname = dirname(fileURLToPath(import.meta.url));
const OUT_DIR = join(__dirname, '..', 'public', 'models', 'vegetation');

/**
 * Deciduous-tree silhouette: thin trunk + rounded canopy. Trunk is a
 * narrow cylinder; canopy is a dome whose base sits at the top of the
 * trunk and whose top reaches Y=1.
 */
function deciduousTree({ trunkR, trunkH, canopyR }) {
  const canopyBaseY = trunkH;
  const canopyH = 1.0 - trunkH;
  return merge([
    cylinder(trunkR, trunkH, 12, 0),
    // Dome built at base 0..canopyH then we need it shifted up to canopyBaseY.
    // Our dome() doesn't take y0, so we shift by hand.
    shiftY(dome(canopyR, canopyH, 16, 6, 0), canopyBaseY),
  ]);
}

/** Conifer silhouette: thin trunk + tall cone. */
function coniferTree({ trunkR, trunkH, canopyR }) {
  const canopyBaseY = trunkH;
  const canopyH = 1.0 - trunkH;
  return merge([
    cylinder(trunkR, trunkH, 12, 0),
    shiftY(cone(canopyR, canopyH, 14, 0), canopyBaseY),
  ]);
}

/** Apply a vertical offset to every Y coordinate of an unindexed mesh. */
function shiftY(mesh, dy) {
  const positions = new Float32Array(mesh.positions);
  for (let i = 1; i < positions.length; i += 3) positions[i] += dy;
  return { positions, normals: mesh.normals, indices: mesh.indices };
}

const KINDS = {
  // Oak: wide rounded canopy, mid trunk, mid green.
  'oak-tree': {
    color: [0.32, 0.55, 0.28],
    build: () => deciduousTree({ trunkR: 0.05, trunkH: 0.25, canopyR: 0.5 }),
  },

  // Pine: narrow conifer, dark green.
  'pine-tree': {
    color: [0.18, 0.4, 0.22],
    build: () => coniferTree({ trunkR: 0.04, trunkH: 0.15, canopyR: 0.35 }),
  },

  // Apple: small deciduous, lighter green.
  'apple-tree': {
    color: [0.5, 0.7, 0.35],
    build: () => deciduousTree({ trunkR: 0.04, trunkH: 0.3, canopyR: 0.45 }),
  },

  // Shrub: no trunk, just a low rounded dome.
  shrub: {
    color: [0.4, 0.6, 0.3],
    build: () => dome(0.5, 1.0, 16, 6),
  },
};

let totalBytes = 0;
let totalKinds = 0;
for (const [kind, spec] of Object.entries(KINDS)) {
  const mesh = spec.build();
  const outPath = join(OUT_DIR, `${kind}.glb`);
  const stats = writeGLB(
    {
      positions: mesh.positions,
      normals: mesh.normals,
      indices: mesh.indices,
      color: spec.color,
      name: kind,
    },
    outPath,
  );
  console.log(
    `wrote ${outPath} (${stats.bytes} bytes, ${stats.vertexCount} verts, ${stats.triangleCount} tris)`,
  );
  totalBytes += stats.bytes;
  totalKinds += 1;
}
console.log(`\n${totalKinds} vegetation kinds, ${totalBytes} bytes total`);
